- Comprehensive details include a breakdown of participant engagement, player performance metrics, and reward distribution within each event; 
- The last completion time refers to the latest time a player completed an event; 
- Average and top scores are measures of player performance within an event; 
- The top rank is the highest position a player achieved in an event's leaderboard; 
- Overall player rating is an aggregate measure of how well players performed across an event.

sql:
SELECT event_id, COUNT(event_top_adv_id) AS total_controls
   FROM event_top_advs
   GROUP BY event_id;

SELECT event_id, MAX(value_1, value_2, value_3) AS max_value
FROM event_top_advs
ORDER BY event_id;

SELECT p.player_name
   FROM players p
   JOIN (
       SELECT player_id, AVG(score) AS avg_player_score
       FROM player_progress
       GROUP BY player_id
   ) t ON p.player_id = t.player_id
   WHERE t.avg_player_score > (
       SELECT AVG(score) FROM player_progress
   );

SELECT event_id, start_time
FROM event_top_advs
WHERE event_id = 123;
